use strict;
use warnings;
use Storable qw(nstore retrieve);

sub save_session {
    my ($session_id, $session_data) = @_;
    nstore($session_data, "/tmp/sess_$session_id");
}

sub load_session {
    my ($session_id) = @_;
    return retrieve("/tmp/sess_$session_id") if -e "/tmp/sess_$session_id";
}

# Example usage
my $session_id = 'some-unique-id';
my $session_data = { name => 'John Doe' };
save_session($session_id, $session_data);

my $loaded_session = load_session($session_id);
if (defined $loaded_session) {
    print "Loaded session: ", Dump($loaded_session), "\n";
} else {
    print "No session found for ID $session_id\n";
